  return Object.entries(permissions)
    .map(([name, level]) => {
      const scope = permissionScopeForRulePermission(name, level);

      if (scope === null) {
        throw new Error(`unsupported token policy rule permission: ${name}:${level}`);
      }

      return scope;
    })
    .sort()
    .join(" ");
